def _select_tip_with_weights(self):
    """Select a tip key from TIPS, biased by self.tip_weights, without mutating TIPS."""
    keys = list(TIPS.keys())
    weights = [max(self.tip_weights.get(key, 1.0), 0.0) for key in keys]
    total_weight = sum(weights)

    if total_weight <= 0:
        return self.rng.choice(keys)

    probabilities = [weight / total_weight for weight in weights]
    threshold = self.rng.random()
    cumulative = 0.0
    for key, probability in zip(keys, probabilities):
        cumulative += probability
        if threshold < cumulative:
            return key

    return keys[-1]

def _truncate_description_at_sentence_boundary(self, description, max_chars):
    """Truncate description to the last full sentence that fits within max_chars, appending an ellipsis."""
    if description is None or max_chars is None or len(description) <= max_chars:
        return description

    sentence_boundaries = [". ", "! ", "? "]
    best_end = -1
    for boundary in sentence_boundaries:
        idx = description.rfind(boundary, 0, max_chars)
        if idx != -1:
            best_end = max(best_end, idx + len(boundary))

    if best_end == -1:
        return description[:max_chars - 1] + "…"

    truncated = description[:best_end] + "…"
    if len(truncated) >= max_chars:
        truncated = description[:max_chars - 1] + "…"

    return truncated

